export function getDrama(id: number) { return DRAMAS.find((d) => d.id === id); }

export function getEpisodes(dramaId: number): Episode[] {
  const data = EPISODES_DATA[dramaId] || [];
  const imgs = IMAGES[dramaId] || [];
  return data.map((d, i) => ({
    id: dramaId * 100 + (i + 1),
    dramaId,
    number: i + 1,
    title: d.title,
    synopsis: d.synopsis,
    teaser: d.teaser,
    image: imgs[i] || YUNA_PHOTO,
  }));
}

export function searchDramas(query: string) {
  const q = query.toLowerCase();
  return DRAMAS.filter((d) => d.title.toLowerCase().includes(q) || d.genre.toLowerCase().includes(q));
}

export function getRandomEpisode() {
  const drama = DRAMAS[Math.floor(Math.random() * DRAMAS.length)]!;
  const eps = getEpisodes(drama.id);
  const episode = eps[Math.floor(Math.random() * eps.length)]!;
  return { drama, episode };
}
